import{_ as a,o as t,c as r,ag as i}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"RxJS Wiki — Content Index","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),o={name:"index.md"};function s(l,e,n,c,h,p){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="rxjs-wiki-—-content-index" tabindex="-1">RxJS Wiki — Content Index <a class="header-anchor" href="#rxjs-wiki-—-content-index" aria-label="Permalink to &quot;RxJS Wiki — Content Index&quot;">​</a></h1><blockquote><p>Catalog of all wiki pages. The LLM reads this first when answering queries. Updated on every ingest or page addition.</p></blockquote><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><ul><li><a href="./overview.html">RxJS Overview</a> — High-level synthesis: what RxJS is, core mental model, operator families, architecture role, key pitfalls</li></ul><hr><h2 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h2><p>RxJS primitives and building blocks.</p><ul><li><a href="./core/Observable.html">Observable</a> — Lazy push-based collection; cold vs hot; marble notation; pipe() composition</li><li><a href="./core/Observer.html">Observer</a> — Consumer interface (next/error/complete); SafeSubscriber guarantees</li><li><a href="./core/Subscription.html">Subscription</a> — Handle to a running Observable; teardown logic; memory leak prevention</li><li><a href="./core/Subject.html">Subject</a> — Multicast Observable + Observer; action bus; cold→hot bridge</li><li><a href="./core/subjects-guide.html">Subjects — Complete Guide</a> — All four variants compared; three roles; choosing guide; pitfalls; Subject vs shareReplay</li><li><a href="./core/BehaviorSubject.html">BehaviorSubject</a> — Subject with current value; state container; <code>.value</code> accessor</li><li><a href="./core/ReplaySubject.html">ReplaySubject</a> — Subject with N-value replay buffer; late-join streams; cache</li><li><a href="./core/AsyncSubject.html">AsyncSubject</a> — Emits only last value on complete; Promise analog</li><li><a href="./core/Scheduler.html">Scheduler</a> — Controls execution timing; asyncScheduler, animationFrameScheduler, VirtualTime</li><li><a href="./core/operators.html">Operators Overview</a> — All operator families: creation, transformation, filtering, combination, error handling, multicasting, utility; first-order vs higher-order</li><li><a href="./core/hot-cold.html">Hot and Cold Observables</a> — Precise definition via subscription side effects; temperature conversion (publish/defer); built-in temperature table; when to share</li><li><a href="./core/custom-operators.html">Custom Operators and pipe()</a> — pipe() as composition operator; custom operators via pipe factory; parametric operators; low-level Observable constructor pattern</li><li><a href="./core/operator-policies.html">Operator Policies — Eight-Policy Framework</a> — Start/Emit/Completion/State/Cancellation/Error/Output Type/Input Type; type chain rule; strongly typed Action/Reducer</li><li><a href="./core/observable-internals.html">Observable Internals</a> — Building Observable from scratch; SafeObserver guarantees; operator pattern; Iterator + Observer synthesis; Observable vs Promise</li><li><a href="./core/combine-latest.html">combineLatest — Formal Rules</a> — Five rules: initial sync, any-source trigger, latest retention, all-complete, error propagation; EMPTY trap; cold observable trap</li><li><a href="./core/share-replay.html">shareReplay — Caching and Multicasting</a> — HTTP caching pattern; refCount true/false; fixed TTL (windowTime); sliding TTL with defer; manual invalidation; error replay pitfall</li><li><a href="./core/execution-phases.html">RxJS Execution Phases</a> — Plan phase (lazy blueprint) vs Execution phase (subscribe triggers); lossy vs non-lossy operators; scheduler as dispatcher bridge</li><li><a href="./core/combination-operators.html">Combination Operators — Complete Reference</a> — Decision tree; per-operator reference: combineLatest, concat, forkJoin, merge, race, withLatestFrom, zip, pairwise, startWith; comparison table</li><li><a href="./core/frp-concepts.html">FRP Concepts — Behaviors and Events</a> — Classic FRP origins: Behavior (continuous, Time→A) vs Event (discrete, [(Time,A)]); fold-events-into-behavior = scan; inputs→combinators→outputs pattern; how RxJS maps to classic FRP</li><li><a href="./core/dataflow-model.html">RxJS as a Dataflow Model</a> — Observable pipelines as directed graphs; operators as nodes; Unix pipe philosophy; OperatorFunction as universal interface; higher-order operators as nested subgraphs</li><li><a href="./core/stream-machines.html">Stream Machine Calculus</a> — 6 irreducible machines: sampleOn, recomputeLatest, reduceState, flattenWithPolicy, composeTopology, shareExecution; two vocabulary layers (teaching DSL + runtime DSL); complete operator→machine map; 8 classification axes</li><li><a href="./core/higher-order-operators.html">Higher-Order Operators — Complete Deep Dive</a> — switchMap / mergeMap / concatMap / exhaustMap with marble diagrams; the *All variants; expand for recursion; error handling inside inners; memory leak patterns; decision guide by use case</li></ul><hr><h2 id="history" tabindex="-1">History <a class="header-anchor" href="#history" aria-label="Permalink to &quot;History&quot;">​</a></h2><p>RxJS version history and migration guides.</p><ul><li><a href="./history/timeline.html">Timeline</a> — From Rx.NET (2009) to RxJS 8; key people; version milestones</li><li><a href="./history/erik-meijer.html">Erik Meijer</a> — Mathematical foundations: the IEnumerable/IObservable dual, Raven Test origin, games as stream transformations, combineLatest stolen from spreadsheets</li><li><a href="./history/rxjs5-to-6.html">RxJS 5 → 6 Migration</a> — The pipe() revolution; import path changes; rxjs-compat migration strategy</li><li><a href="./history/rxjs6-to-7.html">RxJS 6 → 7 Migration</a> — TypeScript rewrite; lastValueFrom; throwError factory; share() config</li></ul><hr><h2 id="patterns" tabindex="-1">Patterns <a class="header-anchor" href="#patterns" aria-label="Permalink to &quot;Patterns&quot;">​</a></h2><p>Proven solutions to recurring reactive programming problems.</p><ul><li><a href="./patterns/">Patterns Index</a> — Quick reference recipes: search, polling, form submit, combining state, cleanup</li><li><a href="./patterns/animations.html">Animations Pattern</a> — animationFrameScheduler; velocity vs duration-based animations; defer for lazy timestamps; easing; tween with switchMap; higher-order reuse</li><li><a href="./patterns/domain-operators.html">Domain Operators Pattern</a> — Wrap operator chains in business-named functions; layered architecture; testability; error isolation; anti-patterns</li><li><a href="./patterns/mvu.html">MVU Pattern</a> — Model–View–Update (Elm-like): action→reducer→state→view with scan</li><li><a href="./patterns/effects.html">Effects Pattern</a> — NgRx-style Action In → Action Out; switchMap vs exhaustMap choice; error handling in effects</li><li><a href="./patterns/state-management.html">State Management</a> — BehaviorSubject store; scan-based reducer; selectors; immutable updates</li><li><a href="./patterns/error-handling.html">Error Handling</a> — catchError inside inner; retry; exponential backoff; graceful degradation</li><li><a href="./patterns/state-machine.html">State Machine Pattern</a> — scan+action stream (MVU-style) and expand-based recursive approach; testing; composability vs XState</li></ul><hr><h2 id="architectures" tabindex="-1">Architectures <a class="header-anchor" href="#architectures" aria-label="Permalink to &quot;Architectures&quot;">​</a></h2><p>Complete application architectures using RxJS.</p><ul><li><a href="./architectures/">Architectures Index</a> — Comparison table; common principles; dependency graph</li><li><a href="./architectures/mvu.html">MVU Architecture</a> — Full wiring: action$, reducer, state$, selectors, effects, view binding, cleanup</li><li><a href="./architectures/redux-observable.html">redux-observable</a> — Epics pattern; RTK integration; comparison vs custom MVU</li><li><a href="./architectures/event-driven.html">Event-Driven Architecture</a> — Typed event bus; micro-frontend communication; request/response over bus</li><li><a href="./architectures/xstate-vs-rxjs.html">XState vs RxJS</a> — Control graph vs dataflow graph; traffic light example; pedestrian button as the deciding test; when to use each</li></ul><hr><h2 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h2><p>Testing strategies for Observable streams and RxJS-based systems.</p><ul><li><a href="./testing/">Testing Index</a> — Testing layers (reducer, operator, effect, state); vitest config; quick patterns</li><li><a href="./testing/marble-testing.html">Marble Testing</a> — Marble syntax; cold/hot Observables; expectObservable; testing switchMap vs mergeMap</li><li><a href="./testing/TestScheduler.html">TestScheduler</a> — Virtual time; run() API; time(), cold(), hot(), expectSubscriptions; complete examples</li></ul><hr><h2 id="debugging" tabindex="-1">Debugging <a class="header-anchor" href="#debugging" aria-label="Permalink to &quot;Debugging&quot;">​</a></h2><p>Techniques for diagnosing and fixing RxJS problems.</p><ul><li><a href="./debugging/">Debugging Index</a> — Debugging checklist; tap workflow; subscription tracking; DevTools integration</li><li><a href="./debugging/tap.html">tap Operator</a> — Side effects and debugging; named tap helper; finalize; tap vs map</li><li><a href="./debugging/common-mistakes.html">Common Mistakes</a> — 13 most common RxJS pitfalls with diagnosis and fixes</li></ul><hr><h2 id="operations-log" tabindex="-1">Operations Log <a class="header-anchor" href="#operations-log" aria-label="Permalink to &quot;Operations Log&quot;">​</a></h2><p>See <a href="./log.html">log</a> for the chronological history of wiki changes.</p>',32)])])}const d=a(o,[["render",s]]);export{u as __pageData,d as default};
